import{_ as e,o as t,c as i,a2 as a}from"./chunks/framework.DPJSKfgD.js";const k=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[],"relativePath":"tests/index.md","filePath":"tests/index.md"}'),n={name:"tests/index.md"};function d(r,s,h,o,l,p){return t(),i("div",null,[...s[0]||(s[0]=[a('<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h1><p>qliff&#39;s tests run as an &quot;exam&quot; framework, adapted from <a href="https://github.com/plutoniumm/qudit" target="_blank" rel="noreferrer">plutoniumm/qudit</a>.</p><p>Each test file is a standalone script. It builds an <code>Exam</code> over a <code>Question</code> subclass, runs it, and emits a <strong>markdown report</strong> next to the console pass/fail summary.</p><p>Every report is a <code>Test | What it does | Result</code> table: one row per test, with a ✅ / ❌ / ⚠️ / ⏭️ result. Failures get full tracebacks in a <code>## Failures</code> section below the table.</p><p>These reports publish straight into this site.</p><h2 id="running-the-tests" tabindex="-1">Running the tests <a class="header-anchor" href="#running-the-tests" aria-label="Permalink to &quot;Running the tests&quot;">​</a></h2><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Reports land in <code>test/_reports/</code> by default (gitignored). To surface them in these docs, point the harness at <code>docs/tests/</code> with the <code>MDR_OUT</code> variable:</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MDR_OUT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/docs/tests&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Each test file emits one markdown file into that directory:</p><table tabindex="0"><thead><tr><th>Test file</th><th>Report</th><th>Covers</th></tr></thead><tbody><tr><td><code>test/smoke.py</code></td><td><code>smoke.md</code></td><td>Build + import smoke test</td></tr><tr><td><code>test/tableau.py</code></td><td><code>tableau.md</code></td><td>CHP tableau gate correctness</td></tr><tr><td><code>test/measure.py</code></td><td><code>measure.md</code></td><td>Measurement outcomes and statistics</td></tr></tbody></table><p>The VitePress sidebar picks up any <code>*.md</code> in <code>docs/tests/</code> automatically. A fresh report shows up under <strong>Testing</strong> with no extra wiring.</p><p>The reports are gitignored; this <code>index.md</code> is the only checked-in file here. Regenerate them whenever you want current results.</p><h2 id="building-the-docs-with-reports" tabindex="-1">Building the docs with reports <a class="header-anchor" href="#building-the-docs-with-reports" aria-label="Permalink to &quot;Building the docs with reports&quot;">​</a></h2><p>A one-liner to refresh the reports and build the static site:</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MDR_OUT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/docs/tests&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>',16)])])}const u=e(n,[["render",d]]);export{k as __pageData,u as default};
